window.__QUIZ_DATA__=[{"id":"theory>Biology>2010>1>a>i","subject":"Biology","year":"2010","type":"Theory","sub_label":"i","group":"","topic":"CONCEPT OF LIVING : RESPIRATORY SYSTEM","question":"Write the chemical equation for an aerobic respiration","images":[],"marking_scheme":"Aerobic respiration  C6H12O6 + 6O2 \u2192 6CO2 + 6H2O + 38ATP Energy/690k cal","marks":"2","difficulty":"1"},{"id":"theory>Biology>2010>1>a>ii","subject":"Biology","year":"2010","type":"Theory","sub_label":"ii","group":"","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"Write the chemical equation for an anaerobic respiration in plants.","images":[],"marking_scheme":"Anaerobic respiration in plants  C6H12O6 \u2192 2CH3OH(OH)COOH + 2ATP/Energy/150k cal  C6H12O6 \u2192 2C3H6O3 + 2ATP/Energy/150k cal","marks":"2","difficulty":"1"},{"id":"theory>Biology>2010>1>a>iii","subject":"Biology","year":"2010","type":"Theory","sub_label":"iii","group":"","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"Write the chemical equation for an anaerobic respiration in animals.","images":[],"marking_scheme":"Anaerobic Respiration in Animals   C6H12O6 \u2192 2CH3OH(OH)COOH + 2ATP/150 kcal  C6H12O6 \u2192 2C3H6O3 + 2ATP/150 kcal","marks":"2","difficulty":"1"},{"id":"theory>Biology>2010>1>b","subject":"Biology","year":"2010","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"CONCEPT OF LIVING : EXCRETORY SYSTEMS","question":"State four functions which the liver of a patient suffering from cancer of the liver will not be able to perform.","images":[],"marking_scheme":"A cancerous liver will not be able to   - Regulate blood sugar  - Produce bile  - Carry out detoxication / denomination / regulation of blood proteins  - Form red blood cells  - Produce heat  - Store iron   - Reserve blood","marks":"2","difficulty":"2"},{"id":"theory>Biology>2010>1>c","subject":"Biology","year":"2010","type":"Theory","sub_label":"c","group":"","topic":"CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.","question":"Make a diagram 8 - 10cm long of a flame cell and label fully.","images":["data:image/png;base64,"],"marking_scheme":"","marks":"2","difficulty":"3"},{"id":"theory>Biology>2010>1>d>i","subject":"Biology","year":"2010","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CONCEPT OF LIVING : HORMONAL COORDINATION","question":"Name one appropriate hormone each responsible for the ripening of fruits","images":[],"marking_scheme":"Ripening of fruit - Auxin / ethane / ethylene / IAA","marks":"2","difficulty":"1"},{"id":"theory>Biology>2010>1>d>ii","subject":"Biology","year":"2010","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : HORMONAL COORDINATION","question":"Name one appropriate hormone each responsible for the breaking dormancy in seeds.","images":[],"marking_scheme":"1. Breaking of dormancy in seeds - 2, 4 - Dichlorophenoxy acetic acid / Auxin","marks":"2","difficulty":"1"},{"id":"theory>Biology>2010>1>d>iii","subject":"Biology","year":"2010","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : HORMONAL COORDINATION","question":"Name one appropriate hormone each responsible for the weed control.","images":[],"marking_scheme":"Weed Control - 2, 4 - Dichlorophenoxyacetic acid","marks":"2","difficulty":"1"},{"id":"theory>Biology>2010>1>d>iv","subject":"Biology","year":"2010","type":"Theory","sub_label":"iv","group":"CLOSENESS","topic":"CONCEPT OF LIVING : HORMONAL COORDINATION","question":"Name one appropriate hormone each responsible for the leaf fall.","images":[],"marking_scheme":"Hormones responsible  Leaf fall - Abscisic acid","marks":"2","difficulty":"1"},{"id":"theory>Biology>2010>2>a>i","subject":"Biology","year":"2010","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"Name two types of germination of seeds giving one example of each type.","images":[],"marking_scheme":"Types of germination with examples  Epigeal germination: Cowpea, bean seed","marks":"5","difficulty":"2"},{"id":"theory>Biology>2010>2>a>ii","subject":"Biology","year":"2010","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"Describe a simple experiment to demonstrate that oxygen, water and warmth are necessary for germination of seeds.","images":[],"marking_scheme":"Experiment to demonstrate factors necessary for germination.  Some dry cotton wool are placed at the bottom of each of conical flasks labelled A, B and D.  - In flask A, few / 2 - 4 bean seeds are placed on dry cotton wool. The flask is placed in a warm place.  - In flask B, the cotton wool is moistened together with seeds in it.  - Test tube containing pyrogallic acid and caustic soda/pyrogallol is suspended in flask B to absorb oxygen, flask B is put in warm place.  - In flask C, a little water is placed on the cotton wool and seeds and it is placed in a warm place.  - In flask D, a little water is poured on the seeds to moisten them and it is placed in the refrigerator.  - The four flasks are observed for four to five days, only the seeds in flask C germinated. This shows that oxygen / water / moisture and warmth are necessary for seed germination.","marks":"5","difficulty":"2"},{"id":"theory>Biology>2010>2>b>i","subject":"Biology","year":"2010","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : HABITATS","question":"State two distinguishing features of epiphytes.","images":[],"marking_scheme":"- A plant which grows on/supported by another plant/lives on trees where it competes with other producers for sunlight.  It doesn't take manufacture food from the support. It is capable of photosynthesis.","marks":"3","difficulty":"1"},{"id":"theory>Biology>2010>2>b>ii","subject":"Biology","year":"2010","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ECOLOGICAL MANAGEMENT : BIOLOGICAL ASSOCIATIONS","question":"State two distinguishing features of parasites.","images":[],"marking_scheme":"- An organism that lives on or in another organism called a host. It obtains shelter/protection / food from the host. At the expense of the host, leading to harm/death of the host.","marks":"4","difficulty":"1"},{"id":"theory>Biology>2010>2>c","subject":"Biology","year":"2010","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ECOLOGICAL MANAGEMENT : BIOLOGICAL ASSOCIATIONS","question":"Give two example of parasitic plants.","images":[],"marking_scheme":"Examples of plant parasites  - Dodder  - Striga  - Mistle toe  - Cassytha filiformis","marks":"5","difficulty":"1"},{"id":"theory>Biology>2010>3>a>i","subject":"Biology","year":"2010","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL COMPONENTS","question":"Write short notes on ecological niche.","images":[],"marking_scheme":"Niche: refers to a specific portion of a habitat/dwelling place which is occupied by a particular species of organism. It is also a functional position/role of an organism within the community .  - Each organism living in the same habitat has its living space and source of food and tolerance for the effect of the habitat.","marks":"5","difficulty":"2"},{"id":"theory>Biology>2010>3>a>ii","subject":"Biology","year":"2010","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : POPULATION STUDIES BY SAMPLING","question":"Write short notes on population density.","images":[],"marking_scheme":"Population density: It is a number of individual organisms of the same species per unitarea/volume of the habitat at a particular time.  It determines the interaction between members of the same species and members of other species. It is mathematically expressed as   Total population / Population sizeArea of habitat  - It is estimated in humans/animals by counting  - It is estimated in plants by quadrat","marks":"4","difficulty":"1"},{"id":"theory>Biology>2010>3>a>iii","subject":"Biology","year":"2010","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"ECOLOGY OF POPULATION : ECOLOGICAL SUCCESSION","question":"Write short notes on climax community.","images":[],"marking_scheme":"Climax community: is established when a stable/unchanging community is attained in ecological succession, the community is in equilibrium with the environment, the vegetation reaches the highest development, and the same species of animals, and plants / organisms re-occurs from year to year.","marks":"5","difficulty":"1"},{"id":"theory>Biology>2010>3>b","subject":"Biology","year":"2010","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM","question":"Describe briefly the interaction between abiotic and biotic components of an ecosystem.","images":[],"marking_scheme":"Interaction between biotic and abiotic components of an ecosystem.  In an ecosystem, the abiotic factors are non-living things (carbonoxide, oxygen, sunlight, soil, water e.t.c) while the biotic components are plants and animal. Green plants use carbondioxide in the presence of sunlight to produce carbohydrate/starch/food. Animals/herbivores feed on carbohydrates/plants and release carbondioxide from respiration, decomposers breakdown dead plants/animals/organic matter to release nutrients to the soil, these nutrients are absorbed by plants for use in food production/photosynthesis, plants give out oxygen during photosynthesis which is used by animals for respiration.","marks":"6","difficulty":"2"},{"id":"theory>Biology>2010>4>a","subject":"Biology","year":"2010","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS","question":"List four characteristics which can be genetically transmitted in humans.","images":[],"marking_scheme":"Inheritable Characters  1. Skin  2. Hair  3. Eye  4. Height","marks":"5","difficulty":"2"},{"id":"theory>Biology>2010>4>b>i","subject":"Biology","year":"2010","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"Name two sites each in plants and animals where meiosis occurs.","images":[],"marking_scheme":"Site of meiosis  * In plants - Antheridium/archegonium, anthers, ovary, sporangium, spore capsule.  * In animals - Testes, ovaries.","marks":"3","difficulty":"2"},{"id":"theory>Biology>2010>4>b>ii","subject":"Biology","year":"2010","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.","question":"State two differences between meiosis and mitosis.","images":[],"marking_scheme":"Differences between Meiosis and Mitosis  MitosisMeiosis1. Nucleus divides only onceNucleus divides twice2. Number of chromosomes remains the same after division diploid Number of chromosomes is halved after division/haploid3. Homologous chromosomes do not associateHomologous chromosomes associate to form bivalents4. Chiasmata are never formed Chiasmata are formed5. Crossing over never occursCrossing over occurs6. Daughter cell identical to parent cell Daughter cells generally different from parent cell.7. Two daughter cells are formedFour daughter cells are formed8. Chromosomes form single row at the equatorChromosomes form double rows at the equator.","marks":"6","difficulty":"2"},{"id":"theory>Biology>2010>4>c>i","subject":"Biology","year":"2010","type":"Theory","sub_label":"i","group":"","topic":"BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS","question":"A woman with blood group 'A' (heterozygous) claimed that her son who has blood group 'O' was fathered by Mr. James who has blood group 'A' (homozygous). With the aid of suitable genetic diagrams. Prove or disprove the woman's claim.","images":["data:image/png;base64,"],"marking_scheme":"Woman blood group - AO {heterozygous}  Father blood group - AA {homozygous}","marks":"3","difficulty":"3"},{"id":"theory>Biology>2010>4>c>ii","subject":"Biology","year":"2010","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS","question":"A woman with blood group 'A' (heterozygous) claimed that her son who has blood group 'O' was fathered by Mr. James who has blood group 'A' (homozygous). With the aid of suitable genetic diagrams.  Give reasons to support your answer.","images":[],"marking_scheme":"(i) The woman's claim is wrong:  (ii) Half their children are heterozygous blood group A and half homozygous blood group A  (iii) No child is group O","marks":"3","difficulty":"3"},{"id":"theory>Biology>2010>5>a>i","subject":"Biology","year":"2010","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS","question":"What is placentation?","images":[],"marking_scheme":"Placentation: This is the arrangement of ovules within the ovary.","marks":"2","difficulty":"1"},{"id":"theory>Biology>2010>5>a>ii","subject":"Biology","year":"2010","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS","question":"Name two organs associated with the human placenta","images":[],"marking_scheme":"Organs associated with human placenta -  Umbilical cord  Uterus","marks":"3","difficulty":"1"},{"id":"theory>Biology>2010>5>b","subject":"Biology","year":"2010","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS","question":"State five functions of the human placenta.","images":[],"marking_scheme":"Functions of Placenta  - Establishes connection between the embryo and the mother.  - Carries oxygen / water / food / nutrients from mother's blood to foetus.  - Removes waste / urea / salt / carbondioxide from foetus blood of mother's blood for elimination.  - Produces progesterone/hormone for maintenance of uterine wall.  - Carries antibodies from mother's blood to foetus.","marks":"5","difficulty":"2"},{"id":"theory>Biology>2010>5>c>i","subject":"Biology","year":"2010","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"Write short note on Viviparity.","images":[],"marking_scheme":"Viviparity: This is the type of reproduction in which the young develops inside the mother's body, obtaining nutrients directly from the parents when fully developed, the young are born alive.","marks":"3","difficulty":"2"},{"id":"theory>Biology>2010>5>c>ii","subject":"Biology","year":"2010","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"Write short note on Territoriality.","images":[],"marking_scheme":"Territoriality: In many animal species, individuals usually  males mark out areas/territories fiercely, chasing away other members of the species, only vigorous individuals are able to establish large territories secure mates and produce many offsprings; territoriality limits overcrowding, animals that carry out this phenomenon are lizards, lions etc.","marks":"4","difficulty":"2"},{"id":"theory>Biology>2010>5>c>iii","subject":"Biology","year":"2010","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"Write short note on Seasonal migration.","images":[],"marking_scheme":"Seasonal Migration: In many habitats, food supply is affected by seasonal changes, food is abundant in rainy seasons but scare in dry season, animals overcome these seasonal food shortages by moving to other habitats during unfavourable, seasons such large scale seasonal movements of animals between habitats are called migrations.  Other causes of migration are temperature changes and breeding seasons.","marks":"3","difficulty":"2"},{"id":"theory>Biology>2010>6>a","subject":"Biology","year":"2010","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION","question":"Explain the term adaptation in relation to the mode of life of an organism.","images":[],"marking_scheme":"Adaptation: These are special features/characteristics that an organism possesses which enable it to live/survive successfully in an environment.","marks":"3","difficulty":"2"},{"id":"theory>Biology>2010>6>b>i","subject":"Biology","year":"2010","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"Explain how this structure adapt the organisms that possess them to their modes of life:    Succulent leaves in Aloe sp.","images":[],"marking_scheme":"Aloe - The succulent leaves are adaptations for water storage   - They are also adapted for surviving high temperature and drought","marks":"2","difficulty":"2"},{"id":"theory>Biology>2010>6>b>ii","subject":"Biology","year":"2010","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"Explain how this structure adapt the organisms that possess them to their modes of life:  Succulent stems and reduced leaves in cactus plants","images":[],"marking_scheme":"Cactus: stems are thick and succulent for water storage; while leaves are reduced to conserve water by reducing rate of transpiration.","marks":"3","difficulty":"2"},{"id":"theory>Biology>2010>6>b>iii","subject":"Biology","year":"2010","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"Explain how this structure adapt the organisms that possess them to their modes of life:  Short, strong beaks in fowls.","images":[],"marking_scheme":"Fowl: The beak is short / strong / straight for picking insects / seed / earthworms / small pieces of food /pecking of feathers.","marks":"2","difficulty":"2"},{"id":"theory>Biology>2010>6>b>iv","subject":"Biology","year":"2010","type":"Theory","sub_label":"iv","group":"CLOSENESS","topic":"EVOLUTION : ADAPTIVE COLOURATION","question":"Explain how this structure adapt the organisms that possess them to their modes of life:  Counter shading in fish.","images":[],"marking_scheme":"Fish: The dorsal side is dark while the ventral side is silvery/counter shading. This dual coloration protects the fish from predators, looking at them from above and below the water.","marks":"2","difficulty":"2"},{"id":"theory>Biology>2010>6>b>v","subject":"Biology","year":"2010","type":"Theory","sub_label":"v","group":"CLOSENESS","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"Explain how this structure adapt the organisms that possess them to their modes of life:  Tiny scale leaves on needle-like branches of pine trees.","images":[],"marking_scheme":"Pines: The needle-like leaves reduce water loss by transpiration, also conserves water for use in the long dry season.","marks":"2","difficulty":"2"},{"id":"theory>Biology>2010>6>c>i","subject":"Biology","year":"2010","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : POPULATION STUDIES BY SAMPLING","question":"What is population?","images":[],"marking_scheme":"Population: This is the total number of individuals of the same species living together in a habitat at a given time.","marks":"2","difficulty":"1"},{"id":"theory>Biology>2010>6>c>ii","subject":"Biology","year":"2010","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ECOLOGY OF POPULATION : FACTORS THAT AFFECT POPULATION","question":"State five effects of overpopulation on a community.","images":[],"marking_scheme":"Effects of Over-population  - Competition for limited resources  - Predation / Cannibalism  - Spread of diseases   - Food shortage  - Build up toxic waste in the environment  - Limited space for individual dwellings  - High mortality/mortality rate  - Increase of social vices/behaviour.","marks":"3","difficulty":"2"}];